settings.custom_liquid:
{%- comment %} ====== EDITABLE VARIABLES — CHANGE THESE ====== {%- endcomment -%}

{%- assign bundle_2_qty    = 3 -%}
{%- assign bundle_2_price  = "23.98" -%}
{%- assign bundle_2_save   = "13.99" -%}
{%- assign bundle_2_label  = "Buy 2 Get 1 Free" -%}
{%- assign bundle_2_tag    = "33% OFF" -%}
{%- assign bundle_2_badge  = "Most Popular" -%}

{%- assign bundle_3_qty    = 5 -%}
{%- assign bundle_3_price  = "35.97" -%}
{%- assign bundle_3_save   = "27.98" -%}
{%- assign bundle_3_label  = "Buy 3 Get 2 Free" -%}
{%- assign bundle_3_tag    = "40% OFF" -%}
{%- assign bundle_3_badge  = "" -%}

{%- assign bundle_cta      = "Add to Cart" -%}
{%- assign bundle_trust    = "Free delivery over $50 · Pay on delivery · Discount applied at checkout" -%}

{%- comment %} ====== DO NOT EDIT BELOW THIS LINE ====== {%- endcomment -%}

{%- assign variant    = product.selected_or_first_available_variant -%}
{%- assign unit_price = product.price -%}

<div class="zbun-wrap" id="zbun-{{ product.id }}">

  <div class="zbun-header">
    <span class="zbun-line"></span>
    <span class="zbun-title">Buy More Save More</span>
    <span class="zbun-line"></span>
  </div>

  <div class="zbun-options">

    <!-- Bundle 1 — Buy 1 -->
    <div
      class="zbun-option zbun-selected"
      data-qty="1"
      data-variant="{{ variant.id }}"
      role="radio" aria-checked="true" tabindex="0"
    >
      <div class="zbun-radio"></div>
      <div class="zbun-opt-body">
        <div class="zbun-opt-top">
          <span class="zbun-opt-label">Buy 1</span>
          <span class="zbun-opt-price">{{ unit_price | money }}</span>
        </div>
        <div class="zbun-opt-sub">Standard price · single item</div>
      </div>
    </div>

    <!-- Bundle 2 -->
    <div
      class="zbun-option"
      data-qty="{{ bundle_2_qty }}"
      data-variant="{{ variant.id }}"
      role="radio" aria-checked="false" tabindex="0"
    >
      <div class="zbun-radio"></div>
      <div class="zbun-opt-body">
        <div class="zbun-opt-top">
          <div class="zbun-opt-left">
            <span class="zbun-opt-label">{{ bundle_2_label }}</span>
            {%- if bundle_2_tag != blank -%}
              <span class="zbun-tag">{{ bundle_2_tag }}</span>
            {%- endif -%}
          </div>
          <div class="zbun-opt-right">
            <span class="zbun-opt-price">${{ bundle_2_price }}</span>
            {%- if bundle_2_save != blank -%}
              <span class="zbun-save">Save ${{ bundle_2_save }}</span>
            {%- endif -%}
          </div>
        </div>
        <div class="zbun-opt-sub">Pay for 2 · get {{ bundle_2_qty }} · discount applies at checkout</div>
      </div>
      {%- if bundle_2_badge != blank -%}
        <span class="zbun-popular">{{ bundle_2_badge }}</span>
      {%- endif -%}
    </div>

    <!-- Bundle 3 -->
    <div
      class="zbun-option"
      data-qty="{{ bundle_3_qty }}"
      data-variant="{{ variant.id }}"
      role="radio" aria-checked="false" tabindex="0"
    >
      <div class="zbun-radio"></div>
      <div class="zbun-opt-body">
        <div class="zbun-opt-top">
          <div class="zbun-opt-left">
            <span class="zbun-opt-label">{{ bundle_3_label }}</span>
            {%- if bundle_3_tag != blank -%}
              <span class="zbun-tag">{{ bundle_3_tag }}</span>
            {%- endif -%}
          </div>
          <div class="zbun-opt-right">
            <span class="zbun-opt-price">${{ bundle_3_price }}</span>
            {%- if bundle_3_save != blank -%}
              <span class="zbun-save">Save ${{ bundle_3_save }}</span>
            {%- endif -%}
          </div>
        </div>
        <div class="zbun-opt-sub">Pay for 3 · get {{ bundle_3_qty }} · discount applies at checkout</div>
      </div>
      {%- if bundle_3_badge != blank -%}
        <span class="zbun-popular">{{ bundle_3_badge }}</span>
      {%- endif -%}
    </div>

  </div>

  <!-- Qty + ATC -->
  <div class="zbun-bottom">
    <div class="zbun-qty-wrap">
      <button class="zbun-q-btn" id="zbun-minus-{{ product.id }}" aria-label="Decrease">
        <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M2 7h10" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/></svg>
      </button>
      <span class="zbun-q-num" id="zbun-num-{{ product.id }}">1</span>
      <button class="zbun-q-btn" id="zbun-plus-{{ product.id }}" aria-label="Increase">
        <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M7 2v10M2 7h10" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/></svg>
      </button>
    </div>
    <button class="zbun-atc-btn" id="zbun-atc-{{ product.id }}">
      <span id="zbun-atc-txt-{{ product.id }}">{{ bundle_cta }}</span>
      <svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M1 8h14M9 2l6 6-6 6" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/></svg>
    </button>
  </div>

  {%- if bundle_trust != blank -%}
    <p class="zbun-trust">🔒 {{ bundle_trust }}</p>
  {%- endif -%}

</div>

<style>
.zbun-wrap { padding: 4px 0 8px; }
.zbun-header { display: flex; align-items: center; gap: 10px; margin-bottom: 14px; }
.zbun-line { flex: 1; height: 1px; background: #EDE4DF; }
.zbun-title { font-size: 13px; font-weight: 700; color: #1A1A1A; white-space: nowrap; }
.zbun-options { display: flex; flex-direction: column; gap: 8px; margin-bottom: 12px; }

.zbun-option {
  position: relative; display: flex; align-items: center; gap: 12px;
  background: #FAF7F4; border: 1.5px solid #EDE4DF; border-radius: 14px;
  padding: 14px 16px; cursor: pointer; user-select: none; outline: none;
  transition: border-color 0.18s, background 0.18s, box-shadow 0.18s;
}
.zbun-option:hover { border-color: #D4A9B0; }
.zbun-option:focus-visible { outline: 2px solid #D4A9B0; outline-offset: 2px; }
.zbun-option.zbun-selected {
  border-color: #6B1A2A; background: rgba(107,26,42,0.025);
  box-shadow: 0 2px 14px rgba(107,26,42,0.09);
}

.zbun-radio {
  width: 20px; height: 20px; border-radius: 50%;
  border: 2px solid #D4A9B0; flex-shrink: 0; position: relative;
  transition: border-color 0.18s;
}
.zbun-radio::after {
  content: ''; width: 10px; height: 10px; border-radius: 50%;
  background: #6B1A2A; position: absolute;
  top: 50%; left: 50%; transform: translate(-50%,-50%) scale(0);
  opacity: 0; transition: opacity 0.18s, transform 0.18s;
}
.zbun-selected .zbun-radio { border-color: #6B1A2A; }
.zbun-selected .zbun-radio::after { opacity: 1; transform: translate(-50%,-50%) scale(1); }

.zbun-opt-body { flex: 1; min-width: 0; }
.zbun-opt-top {
  display: flex; align-items: center;
  justify-content: space-between; gap: 8px; margin-bottom: 3px;
}
.zbun-opt-left { display: flex; align-items: center; gap: 7px; flex-wrap: wrap; }
.zbun-opt-right { display: flex; flex-direction: column; align-items: flex-end; gap: 2px; flex-shrink: 0; }
.zbun-opt-label { font-size: 14px; font-weight: 700; color: #1A1A1A; }
.zbun-opt-price { font-size: 15px; font-weight: 800; color: #1A1A1A; }
.zbun-opt-sub { font-size: 11px; color: #aaa; line-height: 1.4; }

.zbun-tag {
  font-size: 10px; font-weight: 700; color: #fff;
  background: #6B1A2A; padding: 2px 8px;
  border-radius: 100px; white-space: nowrap;
}
.zbun-save {
  font-size: 11px; font-weight: 600; color: #2A6B3A;
  background: rgba(42,107,58,0.1); padding: 1px 7px;
  border-radius: 100px; white-space: nowrap;
}
.zbun-popular {
  position: absolute; top: 0; right: 14px; transform: translateY(-50%);
  font-size: 10px; font-weight: 700; color: #fff;
  background: #6B1A2A; padding: 3px 9px;
  border-radius: 100px; white-space: nowrap;
}

.zbun-bottom { display: flex; align-items: center; gap: 10px; }
.zbun-qty-wrap {
  display: flex; align-items: center;
  border: 1.5px solid #EDE4DF; border-radius: 100px;
  overflow: hidden; background: #fff; flex-shrink: 0;
}
.zbun-q-btn {
  width: 38px; height: 46px; border: none; background: none;
  cursor: pointer; display: flex; align-items: center; justify-content: center;
  color: #6B1A2A; transition: background 0.15s;
}
.zbun-q-btn:hover { background: rgba(107,26,42,0.06); }
.zbun-q-num {
  min-width: 32px; text-align: center; font-size: 14px; font-weight: 700;
  color: #1A1A1A; border-left: 1px solid #EDE4DF;
  border-right: 1px solid #EDE4DF; line-height: 46px; padding: 0 2px;
}
.zbun-atc-btn {
  flex: 1; display: flex; align-items: center; justify-content: center; gap: 8px;
  background: #6B1A2A; color: #fff; border: none; border-radius: 100px;
  font-size: 13px; font-weight: 700; letter-spacing: 0.06em;
  text-transform: uppercase; height: 50px; padding: 0 20px; cursor: pointer;
  transition: background 0.2s, transform 0.15s, gap 0.2s;
}
.zbun-atc-btn:hover { background: #4A1020; transform: translateY(-1px); gap: 12px; }
.zbun-atc-btn:active { transform: scale(0.98); }
.zbun-atc-btn:disabled { background: #999; cursor: not-allowed; transform: none; }
.zbun-trust { font-size: 11px; color: #aaa; margin: 10px 0 0; text-align: center; }

@media (max-width: 480px) {
  .zbun-option { padding: 12px 13px; border-radius: 12px; }
  .zbun-opt-label { font-size: 13px; }
  .zbun-atc-btn { font-size: 12px; }
  .zbun-q-btn { width: 34px; }
}
</style>

<script>
(function () {
  var pid     = '{{ product.id }}';
  var wrap    = document.getElementById('zbun-' + pid);
  if (!wrap) return;

  var options  = wrap.querySelectorAll('.zbun-option');
  var numEl    = document.getElementById('zbun-num-' + pid);
  var minusBtn = document.getElementById('zbun-minus-' + pid);
  var plusBtn  = document.getElementById('zbun-plus-' + pid);
  var atcBtn   = document.getElementById('zbun-atc-' + pid);
  var atcTxt   = document.getElementById('zbun-atc-txt-' + pid);
  var currentQty     = 1;
  var currentVariant = '{{ variant.id }}';
  var bundleMode     = true;

  function selectOpt(opt) {
    options.forEach(function(o) {
      o.classList.remove('zbun-selected');
      o.setAttribute('aria-checked', 'false');
    });
    opt.classList.add('zbun-selected');
    opt.setAttribute('aria-checked', 'true');
    currentQty     = parseInt(opt.dataset.qty, 10);
    currentVariant = opt.dataset.variant;
    numEl.textContent = currentQty;
    bundleMode = true;
  }

  if (options[0]) selectOpt(options[0]);

  options.forEach(function(opt) {
    opt.addEventListener('click', function() { selectOpt(opt); });
    opt.addEventListener('keydown', function(e) {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); selectOpt(opt); }
    });
  });

  function deselect() {
    options.forEach(function(o) {
      o.classList.remove('zbun-selected');
      o.setAttribute('aria-checked', 'false');
    });
    bundleMode = false;
  }

  minusBtn.addEventListener('click', function() {
    if (currentQty > 1) {
      currentQty--;
      numEl.textContent = currentQty;
      if (bundleMode) deselect();
    }
  });
  plusBtn.addEventListener('click', function() {
    currentQty++;
    numEl.textContent = currentQty;
    if (bundleMode) deselect();
  });

  atcBtn.addEventListener('click', function() {
    if (!currentVariant) return;
    atcBtn.disabled = true;
    atcTxt.textContent = 'Adding...';

    fetch('/cart/add.js', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
      body: JSON.stringify({ id: parseInt(currentVariant, 10), quantity: currentQty })
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
      if (data.status) {
        atcTxt.textContent = 'Error — try again';
        atcBtn.disabled = false;
        return;
      }
      atcTxt.textContent = '✓ Added!';
      atcBtn.style.background = '#2A6B3A';
      document.dispatchEvent(new CustomEvent('cart:refresh'));
      document.dispatchEvent(new CustomEvent('cart:updated'));
      var t = document.querySelector(
        '[data-cart-toggle],.cart-toggle,#cart-icon-bubble,.header__icon--cart,[aria-label="Cart"]'
      );
      if (t) t.click();
      setTimeout(function() {
        atcTxt.textContent = '{{ bundle_cta }}';
        atcBtn.style.background = '';
        atcBtn.disabled = false;
      }, 2200);
    })
    .catch(function() {
      atcTxt.textContent = 'Error — try again';
      atcBtn.disabled = false;
    });
  });

  // Sync variant when colour/shade changes
  document.addEventListener('variant:changed', function(e) {
    if (e.detail && e.detail.variant) {
      currentVariant = String(e.detail.variant.id);
      options.forEach(function(o) { o.dataset.variant = currentVariant; });
    }
  });

})();
</script>
